import{_ as e,o as a,c as n,a2 as t}from"./chunks/framework.C24VBsJ9.js";const m=JSON.parse('{"title":"UUU + UMS eMMC Bring-up 实测","description":"","frontmatter":{"title":"UUU + UMS eMMC Bring-up 实测"},"headers":[],"relativePath":"notes/2026-06-08-uuu-ums-emmc-bringup.md","filePath":"notes/2026-06-08-uuu-ums-emmc-bringup.md","lastUpdated":1781369075000}'),i={name:"notes/2026-06-08-uuu-ums-emmc-bringup.md"};function l(p,s,o,r,d,c){return a(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="_2026-06-08-uuu-ums-emmc-bring-up-note" tabindex="-1">2026-06-08 UUU + UMS + eMMC Bring-up Note <a class="header-anchor" href="#_2026-06-08-uuu-ums-emmc-bring-up-note" aria-label="Permalink to &quot;2026-06-08 UUU + UMS + eMMC Bring-up Note&quot;">​</a></h1><h2 id="goal" tabindex="-1">Goal <a class="header-anchor" href="#goal" aria-label="Permalink to &quot;Goal&quot;">​</a></h2><p>Bring up the i.MX6ULL AES board through USB SDP, expose eMMC through UMS, burn a full eMMC image, then boot either:</p><ul><li><code>run netbootaes</code>: TFTP kernel/DTB + NFS rootfs.</li><li><code>run emmcbootaes</code>: eMMC boot partition kernel/DTB + eMMC rootfs.</li></ul><h2 id="conversation-summary" tabindex="-1">Conversation Summary <a class="header-anchor" href="#conversation-summary" aria-label="Permalink to &quot;Conversation Summary&quot;">​</a></h2><ol><li>Initial plan was to avoid unstable fastboot flashing.</li><li>UUU should only boot U-Boot into RAM through USB SDP.</li><li>U-Boot should expose eMMC through UMS.</li><li>The host should not copy only <code>zImage</code>/DTB to a mounted drive letter for production flashing, because that can miss raw U-Boot, partition table, or rootfs.</li><li>Correct full burn flow: use Rufus/DD/raw-image mode to write <code>out/release-latest/images/imx6ull-aes-emmc.img</code> to the UMS-exposed eMMC.</li><li>First UUU lst failed because it referenced <code>u-boot-dtb.imx</code> relative to <code>tools/uuu/</code>.</li><li>Fixed lst to load <code>../../out/release-latest/uboot/u-boot-dtb.imx</code>.</li><li>U-Boot then entered old <code>bootcmd_mfg</code>, which fell through to <code>fastboot 0</code>.</li><li>Fixed board default manufacturing environment so USB/mfgtools boot runs UMS instead of fastboot.</li><li>Updated both U-Boot source and <code>patches/uboot-imx/charlies_board.patch</code>.</li><li>Rebuilt U-Boot at <code>out/release-latest/uboot/u-boot-dtb.imx</code>.</li><li>Verified the new U-Boot image contains:</li></ol><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bootcmd_mfg=echo Run eMMC UMS ...; mmc dev \${emmc_dev}; ums 0 mmc \${emmc_dev};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="files-changed" tabindex="-1">Files Changed <a class="header-anchor" href="#files-changed" aria-label="Permalink to &quot;Files Changed&quot;">​</a></h2><ul><li><code>tools/uuu/imx6ull-aes-ums.lst</code></li><li><code>tools/uuu/README.md</code></li><li><code>third_party/uboot-imx/include/configs/mx6ull_aes_emmc.h</code></li><li><code>patches/uboot-imx/charlies_board.patch</code></li></ul><h2 id="current-u-boot-environment-snapshot" tabindex="-1">Current U-Boot Environment Snapshot <a class="header-anchor" href="#current-u-boot-environment-snapshot" aria-label="Permalink to &quot;Current U-Boot Environment Snapshot&quot;">​</a></h2><p>The board currently reports:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>baudrate=115200</span></span>
<span class="line"><span>bootcmd=echo Current do not autoboot</span></span>
<span class="line"><span>bootcmd_mfg=mmc dev 1; ums 0 mmc 1</span></span>
<span class="line"><span>bootdelay=-1</span></span>
<span class="line"><span>emmc_dev=1</span></span>
<span class="line"><span>ethact=ethernet@20b4000</span></span>
<span class="line"><span>ethprime=eth1</span></span>
<span class="line"><span>loadaddr=0x80800000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>The environment is minimal and needs normal boot variables.</p><h2 id="host-side-assumptions" tabindex="-1">Host-side Assumptions <a class="header-anchor" href="#host-side-assumptions" aria-label="Permalink to &quot;Host-side Assumptions&quot;">​</a></h2><p>TFTP directory:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/tftp</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Files expected in TFTP:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zImage</span></span>
<span class="line"><span>imx6ull-aes.dtb</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>NFS rootfs:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/home/charliechen/imx-forge/rootfs/nfs</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Common tutorial network values:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>board ipaddr = 192.168.60.200</span></span>
<span class="line"><span>serverip     = 192.168.60.1</span></span>
<span class="line"><span>netmask      = 255.255.255.0</span></span>
<span class="line"><span>gatewayip    = 192.168.60.1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="host-preparation" tabindex="-1">Host Preparation <a class="header-anchor" href="#host-preparation" aria-label="Permalink to &quot;Host Preparation&quot;">​</a></h2><p>Copy TFTP files:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/tftp</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/images/zImage</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/tftp/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/images/imx6ull-aes.dtb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/tftp/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> a+r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/tftp/zImage</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/tftp/imx6ull-aes.dtb</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Historical kernel NFS server <code>/etc/exports</code> entry:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/home/charliechen/imx-forge/rootfs/nfs 192.168.60.0/24(rw,sync,no_subtree_check,no_root_squash)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Reload kernel NFS exports:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exportfs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ra</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nfs-kernel-server</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Note: on the newer WSL2 setup, kernel <code>nfs-kernel-server</code> hung on local NFSv3 mounts. Use NFS-Ganesha instead and pin <code>mountport=20048</code>. See:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>document/notes/2026-06-08-wsl2-nfsroot-ganesha-troubleshoot.md</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="u-boot-environment-quick-paste-block" tabindex="-1">U-Boot Environment: Quick Paste Block <a class="header-anchor" href="#u-boot-environment-quick-paste-block" aria-label="Permalink to &quot;U-Boot Environment: Quick Paste Block&quot;">​</a></h2><p>Paste this in U-Boot, adjusting IP values if the host network differs:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>setenv ipaddr 192.168.60.200</span></span>
<span class="line"><span>setenv serverip 192.168.60.1</span></span>
<span class="line"><span>setenv gatewayip 192.168.60.1</span></span>
<span class="line"><span>setenv netmask 255.255.255.0</span></span>
<span class="line"><span>setenv hostname imx6ull-aes</span></span>
<span class="line"><span>setenv nfs_iface eth0</span></span>
<span class="line"><span>setenv loadaddr 0x80800000</span></span>
<span class="line"><span>setenv fdt_addr 0x83000000</span></span>
<span class="line"><span>setenv fdt_addr_r 0x83000000</span></span>
<span class="line"><span>setenv bootfile zImage</span></span>
<span class="line"><span>setenv fdt_file imx6ull-aes.dtb</span></span>
<span class="line"><span>setenv nfsrootdir /home/charliechen/imx-forge/rootfs/nfs</span></span>
<span class="line"><span>setenv nfsargs &#39;setenv bootargs console=ttymxc0,115200 root=/dev/nfs rw nfsroot=\${serverip}:\${nfsrootdir},vers=3,proto=tcp,nolock,port=2049,mountport=20048 ip=\${ipaddr}:\${serverip}:\${gatewayip}:\${netmask}:\${hostname}:\${nfs_iface}:off&#39;</span></span>
<span class="line"><span>setenv netbootaes &#39;run nfsargs; tftp \${loadaddr} \${bootfile}; tftp \${fdt_addr} \${fdt_file}; bootz \${loadaddr} - \${fdt_addr}&#39;</span></span>
<span class="line"><span>setenv emmcargs &#39;setenv bootargs console=ttymxc0,115200 root=/dev/mmcblk1p2 rootfstype=ext4 rootwait rw&#39;</span></span>
<span class="line"><span>setenv emmcdevsetup &#39;mmc dev \${emmc_dev}&#39;</span></span>
<span class="line"><span>setenv loademmcimage &#39;ext4load mmc \${emmc_dev}:1 \${loadaddr} /zImage&#39;</span></span>
<span class="line"><span>setenv loademmcfdt &#39;ext4load mmc \${emmc_dev}:1 \${fdt_addr} /imx6ull-aes.dtb&#39;</span></span>
<span class="line"><span>setenv emmcbootaes &#39;run emmcargs; run emmcdevsetup; run loademmcimage; run loademmcfdt; bootz \${loadaddr} - \${fdt_addr}&#39;</span></span>
<span class="line"><span>setenv bootcmd &#39;run emmcbootaes&#39;</span></span>
<span class="line"><span>setenv bootdelay 1</span></span>
<span class="line"><span>saveenv</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br></div></div><p>Manual test commands:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>run netbootaes</span></span>
<span class="line"><span>run emmcbootaes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>If eMMC rootfs fails with <code>VFS: Cannot open root device</code>, try:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>setenv emmcargs &#39;setenv bootargs console=ttymxc0,115200 root=/dev/mmcblk0p2 rootfstype=ext4 rootwait rw&#39;</span></span>
<span class="line"><span>run emmcbootaes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="current-caveat" tabindex="-1">Current Caveat <a class="header-anchor" href="#current-caveat" aria-label="Permalink to &quot;Current Caveat&quot;">​</a></h2><p><code>out/release-latest/images/imx6ull-aes-emmc.img</code> must be regenerated after U-Boot changes if the image should contain the latest eMMC-resident U-Boot. The temporary UUU U-Boot only runs from RAM.</p>`,40)])])}const h=e(i,[["render",l]]);export{m as __pageData,h as default};
